mapper.insert:
INSERT INTO approvalReference (
    refId, docId, refEmpId, refEmpName,
    refDeptCode, refDeptName,
    refGradeCode, refGradeName
) VALUES (
    approvalReference_seq.NEXTVAL, #{docId},
    #{refEmpId}, #{refEmpName},
    #{refDeptCode}, #{refDeptName},
    #{refGradeCode}, #{refGradeName}
)

mapper.select:
SELECT COUNT(DISTINCT d.docId)
FROM approvalDoc d
LEFT JOIN approvalLine l      ON d.docId = l.docId
LEFT JOIN approvalReference r ON d.docId = r.docId
WHERE d.docStatus != 'DRAFT'
  AND (
      d.writerEmpId = #{empId}
   OR l.apprEmpId   = #{empId}
   OR r.refEmpId    = #{empId}
  )

    AND d.title LIKE '%' || #{keyword} || '%'


    AND d.regDate >= TO_DATE(#{startDate}, 'YYYY-MM-DD')


    AND d.regDate < TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1

mapper.update:
UPDATE approvalDoc
SET docStatus = 'CANCELED'
WHERE docId = #{docId}
  AND writerEmpId = #{empId}
  AND (
      (docStatus = 'REJECTED')
      OR
      (docStatus = 'PENDING'
       AND NOT EXISTS (
           SELECT 1 FROM approvalLine
           WHERE docId = #{docId}
             AND lineStatusCode != 'WAIT'
       ))
  )
